                      <span className="text-sm">
                        {coupon.uses_count ?? 0}
                        {coupon.max_uses ? ` / ${coupon.max_uses}` : ' / ∞'}
                      </span>
                    </TableCell>
                    <TableCell>
                      <span className={`text-sm ${isExpired ? 'text-red-500' : ''}`}>
                        {coupon.expires_at
